// Personalize email content for each contact
const item = $input.item.json;

const firstName = item.first_name || 'Valued Customer';
const lastName = item.last_name || '';
const email = item.email;
const company = item.company || '';

// Build personalized subject and body
const subject = `Hi ${firstName}, Here's Something Special Just for You! 🎉`;

const htmlBody = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    body { font-family: Arial, sans-serif; background-color: #f4f4f4; margin: 0; padding: 0; }
    .container { max-width: 600px; margin: 30px auto; background: #ffffff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
    .header { background-color: #4F46E5; padding: 30px; text-align: center; }
    .header h1 { color: #ffffff; margin: 0; font-size: 26px; }
    .body { padding: 30px; color: #333333; line-height: 1.6; }
    .body h2 { color: #4F46E5; }
    .cta-button { display: inline-block; margin: 20px 0; padding: 14px 32px; background-color: #4F46E5; color: #ffffff; text-decoration: none; border-radius: 6px; font-weight: bold; font-size: 16px; }
    .footer { background-color: #f9f9f9; padding: 20px; text-align: center; font-size: 12px; color: #999999; }
    .footer a { color: #4F46E5; text-decoration: none; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>🚀 Exciting News, ${firstName}!</h1>
    </div>
    <div class="body">
      <h2>We have something special for you</h2>
      <p>Hi ${firstName}${lastName ? ' ' + lastName : ''},</p>
      <p>Thank you for being a valued part of our community${company ? ` at ${company}` : ''}. We're thrilled to share our latest update with you.</p>
      <p>We've been working hard on new features and improvements that we know you'll love. Here's what's new:</p>
      <ul>
        <li>✅ <strong>Feature One</strong> – Streamlined workflow to save you time.</li>
        <li>✅ <strong>Feature Two</strong> – Enhanced analytics dashboard.</li>
        <li>✅ <strong>Feature Three</strong> – Better integrations with your favorite tools.</li>
      </ul>
      <p>Ready to see it in action?</p>
      <a href="https://yourwebsite.com/campaign?ref=${encodeURIComponent(email)}" class="cta-button">Explore Now →</a>
      <p>If you have any questions, just reply to this email — we're always happy to help.</p>
      <p>Warm regards,<br><strong>The Team</strong></p>
    </div>
    <div class="footer">
      <p>You received this email because you're subscribed to our newsletter.</p>
      <p><a href="https://yourwebsite.com/unsubscribe?email=${encodeURIComponent(email)}">Unsubscribe</a> | <a href="https://yourwebsite.com/privacy">Privacy Policy</a></p>
      <p>© 2025 Your Company, Inc. All rights reserved.</p>
    </div>
  </div>
</body>
</html>
`;

return {
  email,
  firstName,
  lastName,
  company,
  subject,
  htmlBody
};

// Log result
const email = $input.item.json.email || 'unknown';
console.log(`Email sent to: ${email}`);

return {
  email,
  status: 'sent',
  timestamp: new Date().toISOString()
};

// Log error
const email = $input.item.json.email || 'unknown';
const error = $input.item.json.error?.message || 'Unknown error';
console.error(`Failed to send email to: ${email}. Error: ${error}`);

return {
  email,
  status: 'failed',
  error,
  timestamp: new Date().toISOString()
};

// Build campaign summary report
const items = $input.all();
const allResults = items.flatMap(i => i.json.data || [i.json]);

const sent = allResults.filter(r => r.status === 'sent').length;
const failed = allResults.filter(r => r.status === 'failed').length;
const total = allResults.length;

const failedEmails = allResults
  .filter(r => r.status === 'failed')
  .map(r => `- ${r.email}: ${r.error}`)
  .join('\n') || 'None';

const report = `
📧 BULK EMAIL CAMPAIGN REPORT
=============================
Date: ${new Date().toUTCString()}

Total Contacts: ${total}
✅ Successfully Sent: ${sent}
❌ Failed: ${failed}
Success Rate: ${total > 0 ? ((sent / total) * 100).toFixed(1) : 0}%

Failed Emails:
${failedEmails}
`;

console.log(report);

return {
  total,
  sent,
  failed,
  successRate: total > 0 ? ((sent / total) * 100).toFixed(1) + '%' : '0%',
  report
};
